// Function Declaration sintaksisi
function funksiyaAdi(parametr1, parametr2) {
  // funksiyanın kodu
  return nəticə;
}

// 'topla' adlı funksiya yaradıram
function topla(a, b) {
  return a + b;
}

// Funksiyanı çağırıram
console.log(topla(2, 3)); // nəticə: 5
console.log(topla(10, 20)); // nəticə: 30

// 'salamVer' adlı funksiya yaradıram
function salamVer(ad) {
  return 'Salam, ' + ad + '!';
}

// Funksiyanı çağırıram
console.log(salamVer('Murad')); // nəticə: Salam, Murad!
console.log(salamVer('Aysel')); // nəticə: Salam, Aysel!

// 'kofeHazirla' funksiyası iki parametr alır
function kofeHazirla(kofeNövü, şəkər) {
  return 'Sənin ' + kofeNövü + ' kofen hazırdır, ' + şəkər + '!';
}

// Funksiyanı çağıranda arqumentlər verirəm
console.log(kofeHazirla('latte', 'şəkərsiz')); // nəticə: Sənin latte kofen hazırdır, şəkərsiz!
console.log(kofeHazirla('espresso', 'şəkərli')); // nəticə: Sənin espresso kofen hazırdır, şəkərli!

// Funksiyanı əvvəlcə çağırıram
console.log(cix(10, 3)); // nəticə: 7

// Sonra funksiyanı yazıram
function cix(a, b) {
  return a - b;
}

// 'salamGoster' funksiyası heç nə qaytarmır
function salamGoster(ad) {
  console.log('Salam, ' + ad + '!');
}

// Funksiyanı çağırıram
salamGoster('Kamran'); // ekrana yazır: Salam, Kamran!

// Return olmadığı üçün undefined qaytarır
let nəticə = salamGoster('Aysel');
console.log(nəticə); // nəticə: undefined

